import{_ as l,c as i,o as n,j as t,ae as o,a as e}from"./chunks/framework.mNpjyZEt.js";const g=JSON.parse('{"title":"About WCI","description":"","frontmatter":{"layout":"home"},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),r={name:"about.md"};function s(d,a,h,c,f,u){return n(),i("div",null,a[0]||(a[0]=[t("br",null,null,-1),t("br",null,null,-1),t("h1",{id:"about-wci",tabindex:"-1"},[e("About WCI "),t("a",{class:"header-anchor",href:"#about-wci","aria-label":'Permalink to "About WCI"'},"​")],-1),t("p",null,[e("The 2026 West Coast Invitational will happen on July 11th, 2026, from 8 AM - 6 PM, at "),t("a",{href:"https://www.google.com/maps/place/North+Tapps+Middle+School/@47.248772,-122.1638732,17z/data=!3m1!4b1!4m6!3m5!1s0x5490f73ea028b96d:0x97264a345bf74725!8m2!3d47.248772!4d-122.1612983!16s%2Fm%2F076dmmf?entry=ttu&g_ep=EgoyMDI2MDUyMC4wIKXMDSoASAFQAw%3D%3D",target:"_blank",rel:"noreferrer"},"North Tapps Middle School"),e(" (20029 12th St E, Bonney Lake, WA 98391).")],-1),t("iframe",{src:"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d2708.354444887927!2d-122.16387322387503!3d47.24877197115928!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x5490f73ea028b96d%3A0x97264a345bf74725!2sNorth%20Tapps%20Middle%20School!5e0!3m2!1sen!2sus!4v1779767248893!5m2!1sen!2sus",width:"600",height:"450",style:{border:"0"},allowfullscreen:"",loading:"lazy",referrerpolicy:"no-referrer-when-downgrade"},null,-1),o('<h2 id="venue-parking-information" tabindex="-1">Venue &amp; Parking Information <a class="header-anchor" href="#venue-parking-information" aria-label="Permalink to &quot;Venue &amp; Parking Information&quot;">​</a></h2><ul><li><strong>Parking Information:</strong> Parking is available on site at North Tapps Middle School&#39;s parking lot.</li><li><strong>Arrival Time:</strong> See the <a href="./about#schedule">schedule below</a>.</li></ul><h2 id="schedule" tabindex="-1">Schedule <a class="header-anchor" href="#schedule" aria-label="Permalink to &quot;Schedule&quot;">​</a></h2><ul><li>Our current (tentative) schedule for the event can be found below.</li><li>We will be running one field this year (along with a practice field).</li><li>Please note that the <strong>times listed below are only estimates</strong> and are subject to change!</li></ul><table tabindex="0"><thead><tr><th style="text-align:left;">Time</th><th style="text-align:left;">What</th></tr></thead><tbody><tr><td style="text-align:left;">7:30 AM to 8:00 AM</td><td style="text-align:left;">Volunteers Arrive</td></tr><tr><td style="text-align:left;">8:30 AM</td><td style="text-align:left;">Venue Opens</td></tr><tr><td style="text-align:left;">8:30 AM to 9:30 AM</td><td style="text-align:left;">Team Check-in</td></tr><tr><td style="text-align:left;">9:00 AM to 10:30 AM</td><td style="text-align:left;">Team Robot Inspection</td></tr><tr><td style="text-align:left;">9:30 AM to 10:30 AM</td><td style="text-align:left;">Practice Matches</td></tr><tr><td style="text-align:left;">10:45 AM to 11:30 AM</td><td style="text-align:left;">Opening Ceremonies/Driver&#39;s Meeting</td></tr><tr><td style="text-align:left;">11:30 AM to 12:00 PM</td><td style="text-align:left;">Qualification Matches</td></tr><tr><td style="text-align:left;">12:00 PM to 12:45 PM</td><td style="text-align:left;">Lunch</td></tr><tr><td style="text-align:left;">12:45 PM to 3:45 PM</td><td style="text-align:left;">Qualification Matches</td></tr><tr><td style="text-align:left;">4:00 PM to 4:15 PM</td><td style="text-align:left;">Alliance Selection</td></tr><tr><td style="text-align:left;">4:30 PM to 6:00 PM</td><td style="text-align:left;">Playoff Matches</td></tr><tr><td style="text-align:left;">6:05 PM to 6:15 PM</td><td style="text-align:left;">Closing Ceremonies</td></tr><tr><td style="text-align:left;">6:30 PM</td><td style="text-align:left;">Venue Closes</td></tr><tr><td style="text-align:left;">6:30 PM to 7:30 PM</td><td style="text-align:left;">Teardown</td></tr></tbody></table><h2 id="format" tabindex="-1">Format <a class="header-anchor" href="#format" aria-label="Permalink to &quot;Format&quot;">​</a></h2><ul><li>The event will follow standard 2026 DECODE season format, with a double elimination bracket.</li><li>There will be qualification matches, alliance selection, eliminations, and awards at the end (see <a href="#schedule">schedule</a> for more details).</li></ul><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><ul><li>All <a href="/apply">applications</a> are due by <strong>June 21st, 2026</strong>, at 11:59 PM PDT, and will be reviewed and selected on a rolling basis.</li><li>Accepted teams will receive information regarding how to pay for registration via email.</li></ul><h2 id="payment" tabindex="-1">Payment <a class="header-anchor" href="#payment" aria-label="Permalink to &quot;Payment&quot;">​</a></h2><ul><li>Payment is $50 USD for accepted teams.</li><li>Additionally, you can pay increments of $35 to compete with extra robots, if there is enough space.</li><li>We will <strong>never</strong> ask you for your credit card information on Discord, email, phone call, or other means - all payments will be made through a secure payment processor.</li></ul>',11)]))}const p=l(r,[["render",s]]);export{g as __pageData,p as default};
